import React, { useState, useEffect, useMemo } from 'react';
import { createRoot } from 'react-dom/client';
import { GoogleGenAI, Type } from "@google/genai";
import { motion, AnimatePresence } from "framer-motion";

// --- Tipos y Datos de Enlaces Médicos ---
interface MedicalLink {
  id: string;
  name: string;
  url: string;
  category: 'Clínico' | 'Resultados' | 'Soporte' | 'Administrativo';
  description: string;
  keywords: string[];
  isImportant?: boolean;
}

const MEDICAL_LINKS: MedicalLink[] = [
  { id: 'everest', name: 'EVEREST', url: 'https://appportal.everestintelligent.com/EverHealth/', category: 'Clínico', description: 'Portal principal de gestión de salud EverHealth.', keywords: ['historia clinica', 'pacientes', 'portal'] },
  { id: 'pana', name: 'PANA', url: 'https://nuevaeps.viva1a.com.co/pana/', category: 'Clínico', description: 'Sistema de gestión Nueva EPS.', keywords: ['nueva eps', 'afiliados'] },
  { id: 'digiturno', name: 'DIGITURNO', url: 'http://api.digiturno.viva1a.com.co:85/', category: 'Administrativo', description: 'Gestión de turnos y filas en sala.', keywords: ['turnos', 'filas', 'atencion'] },
  { id: 'mipres', name: 'MIPRES', url: 'https://mipres.sispro.gov.co/MIPRESNOPBS/Login.aspx?ReturnUrl=%2fMIPRESNOPBS', category: 'Clínico', description: 'Prescripción de servicios y tecnologías no PBS.', keywords: ['medicamentos', 'no pbs', 'formular', 'sispro'] },
  { id: 'fichas', name: 'FICHAS EPIDEMIOLÓGICAS', url: 'https://drive.google.com/drive/folders/1DHFZPwH_ZaG5NUTu0NmPYtfmV3ZZTybv?usp=share_link', category: 'Soporte', description: 'Formatos para reporte de eventos en salud pública.', keywords: ['sivigila', 'notificacion', 'epidemiologia'] },
  { id: 'lumier', name: 'LUMIER', url: 'https://lumierdigital.com:8443/login.lu', category: 'Resultados', description: 'Visualizador de imágenes diagnósticas y rayos X.', keywords: ['rx', 'rayos x', 'imagenes', 'radiologia'] },
  { id: 'annarlytics', name: 'ANNARLYTICS', url: 'http://datacare.viva1a.com.co/datacare/#nbb', category: 'Resultados', description: 'Resultados de laboratorio clínico centralizado.', keywords: ['laboratorio', 'examenes', 'sangre', 'resultados'] },
  { id: 'athenea', name: 'ATHENEA', url: 'https://medicosviva1a.atheneasoluciones.com/', category: 'Resultados', description: 'Sistema alterno de resultados médicos.', keywords: ['resultados', 'consulta'] },
  { id: 'agenda_lab', name: 'AGENDA LABORATORIOS', url: 'https://appcita.viva1a.com.co:8051/laboratorio/agente', category: 'Administrativo', description: 'Programación de citas para toma de muestras.', keywords: ['citas', 'agenda', 'muestras'] },
  { id: 'glpi', name: 'MESA DE SERVICIO (GLPI)', url: 'http://mesadeservicios.viva1a.com.co/glpi/index.php', category: 'Soporte', description: 'Reporte de fallas técnicas y soporte IT.', keywords: ['soporte', 'tecnico', 'computador', 'daño', 'ticket'] },
  { id: 'viva_aprendiendo', name: 'VIVA APRENDIENDO', url: 'http://vivaaprendiendo.com.co/', category: 'Soporte', description: 'Plataforma de capacitación continua.', keywords: ['cursos', 'capacitacion', 'aprender'] },
  { id: 'mi_portal', name: 'MI PORTAL GH', url: 'https://www.miportalgh.com/', category: 'Administrativo', description: 'Gestión humana y desprendibles de nómina.', keywords: ['nomina', 'vacaciones', 'talento humano'] },
  { id: 'poblacion_utp', name: 'POBLACION UTP', url: 'https://drive.google.com/drive/folders/1W1cNCvtEbp3Muk5BpISm40qyxvEHox9C?usp=drive_link', category: 'Clínico', description: 'Base de datos población Universidad Tecnológica.', keywords: ['utp', 'estudiantes', 'docentes'] },
  { id: 'contingencia', name: 'CONTINGENCIA MANUAL', url: 'https://drive.google.com/drive/folders/1h3vXmO5xk61g8CVYDZZsry_IuIUZsNmU?usp=sharing', category: 'Soporte', description: 'Formatos para uso cuando el sistema no funciona.', keywords: ['caida sistema', 'manual', 'papel'] },
  { id: 'reporte_inseguro', name: 'ACCIONES INSEGURAS', url: 'https://forms.office.com/Pages/ResponsePage.aspx?id=S6q48XMM30ySUZubC9zVp-nqrrGNgSlLvHS057gXxCRUOFBCVVNKUUs0STBDMzFHRE83TEZJTEhUTy4u', category: 'Soporte', description: 'Reporte de seguridad del paciente.', keywords: ['seguridad', 'evento adverso', 'riesgo'] },
  { id: 'desistimiento', name: 'DESISTIMIENTOS', url: 'https://drive.google.com/drive/folders/1x8Xrrq2o0zMqYGScjddx8W9JedmfUsRd?usp=sharing', category: 'Administrativo', description: 'Formatos de desistimiento de servicios.', keywords: ['no acepta', 'firma', 'paciente'] },
];

const App = () => {
  const [query, setQuery] = useState('');
  const [filteredIds, setFilteredIds] = useState<string[]>(MEDICAL_LINKS.map(l => l.id));
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [showPasswords, setShowPasswords] = useState(false);

  const handleSearch = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!query.trim()) {
      setFilteredIds(MEDICAL_LINKS.map(l => l.id));
      return;
    }

    setIsAiLoading(true);
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

    try {
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `Actúa como un asistente para médicos de Viva1A IPS. Filtra esta lista de enlaces basada en la necesidad del doctor: "${query}".
        Retorna UNICAMENTE un arreglo JSON con los IDs de los enlaces que coinciden.
        Contexto de búsqueda común: "prescribir", "ver fotos de rx", "resultados de sangre", "reportar daño pc".

        Enlaces: ${JSON.stringify(MEDICAL_LINKS.map(l => ({ id: l.id, name: l.name, description: l.description, keywords: l.keywords })))}`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: { type: Type.STRING }
          }
        }
      });

      const resultIds = JSON.parse(response.text || '[]');
      // Si la IA no encuentra nada coherente, hacemos un fallback manual básico
      if (resultIds.length === 0) {
        const manual = MEDICAL_LINKS.filter(l => 
          l.name.toLowerCase().includes(query.toLowerCase()) || 
          l.keywords.some(k => k.includes(query.toLowerCase()))
        ).map(l => l.id);
        setFilteredIds(manual);
      } else {
        setFilteredIds(resultIds);
      }
    } catch (err) {
      console.error("AI Error:", err);
      const fallback = MEDICAL_LINKS.filter(l => 
        l.name.toLowerCase().includes(query.toLowerCase()) || 
        l.description.toLowerCase().includes(query.toLowerCase())
      ).map(l => l.id);
      setFilteredIds(fallback);
    } finally {
      setIsAiLoading(false);
    }
  };

  const categories = ['Clínico', 'Resultados', 'Administrativo', 'Soporte'];
  const displayedLinks = MEDICAL_LINKS.filter(l => filteredIds.includes(l.id));

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 font-sans selection:bg-blue-100">
      {/* Navbar Minimalista */}
      <nav className="sticky top-0 z-50 bg-white/80 backdrop-blur-md border-b border-slate-200">
        <div className="max-w-7xl mx-auto px-6 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center shadow-lg shadow-blue-200">
              <svg className="w-6 h-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13.828 10.172a4 4 0 00-5.656 0l-4 4a4 4 0 105.656 5.656l1.102-1.101m-.758-4.899a4 4 0 005.656 0l4-4a4 4 0 00-5.656-5.656l-1.1 1.1" /></svg>
            </div>
            <h1 className="text-xl font-bold tracking-tight text-slate-800">
              VIVA1A <span className="text-blue-600">LINKS</span>
            </h1>
          </div>
          <button 
            onClick={() => setShowPasswords(!showPasswords)}
            className="flex items-center gap-2 px-4 py-2 text-sm font-medium text-blue-600 hover:bg-blue-50 rounded-full transition-colors"
          >
            {showPasswords ? 'Ocultar Credenciales' : 'Ver Credenciales'}
          </button>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto px-6 py-12">
        {/* Hero & Búsqueda IA */}
        <div className="max-w-3xl mx-auto text-center mb-12">
          <motion.h2 
            initial={{ opacity: 0, y: -20 }}
            animate={{ opacity: 1, y: 0 }}
            className="text-3xl md:text-4xl font-extrabold text-slate-900 mb-4 heading-font"
          >
            ¿En qué podemos ayudarte hoy, Doctor?
          </motion.h2>
          <p className="text-slate-500 mb-8">Escribe lo que necesitas y nuestra IA encontrará el enlace correcto.</p>

          <form onSubmit={handleSearch} className="relative group">
            <div className="absolute -inset-1 bg-gradient-to-r from-blue-500 to-cyan-500 rounded-2xl blur opacity-20 group-focus-within:opacity-40 transition duration-300"></div>
            <div className="relative flex items-center bg-white border border-slate-200 rounded-2xl p-1.5 shadow-sm focus-within:ring-2 focus-within:ring-blue-500 focus-within:border-transparent transition-all">
              <input
                type="text"
                value={query}
                onChange={(e) => setQuery(e.target.value)}
                placeholder="Ej: 'necesito ver exámenes de sangre' o 'quiero formular'..."
                className="w-full bg-transparent px-5 py-3 outline-none text-slate-700 placeholder:text-slate-400"
              />
              <button
                type="submit"
                disabled={isAiLoading}
                className={`px-6 py-3 rounded-xl font-bold transition-all flex items-center gap-2 ${
                  isAiLoading ? 'bg-slate-100 text-slate-400' : 'bg-blue-600 text-white hover:bg-blue-700 active:scale-95'
                }`}
              >
                {isAiLoading ? (
                  <div className="w-5 h-5 border-2 border-slate-300 border-t-slate-500 rounded-full animate-spin"></div>
                ) : 'Buscar con IA'}
              </button>
            </div>
          </form>
          {query && !isAiLoading && (
            <button 
              onClick={() => { setQuery(''); setFilteredIds(MEDICAL_LINKS.map(l => l.id)); }}
              className="mt-4 text-sm text-slate-400 hover:text-blue-600 transition-colors"
            >
              Restablecer filtros
            </button>
          )}
        </div>

        {/* Credenciales Rápidas (Condicional) */}
        <AnimatePresence>
          {showPasswords && (
            <motion.div 
              initial={{ opacity: 0, height: 0 }}
              animate={{ opacity: 1, height: 'auto' }}
              exit={{ opacity: 0, height: 0 }}
              className="mb-12 grid grid-cols-1 md:grid-cols-3 gap-6"
            >
              {[
                { title: 'ANNARLYTICS', user: 'CONSULTA', pass: '123456', color: 'blue' },
                { title: 'LUMIER', user: 'PREMIUM', pass: '123456', color: 'cyan' },
                { title: 'MESA WHATSAPP', qr: true, color: 'emerald' }
              ].map((item, idx) => (
                <div key={idx} className="bg-white border border-slate-200 p-6 rounded-2xl shadow-sm">
                   <h4 className={`text-xs font-bold uppercase tracking-widest text-${item.color}-600 mb-3`}>{item.title}</h4>
                   {item.qr ? (
                     <div className="flex items-center gap-4">
                       <img src="https://api.qrserver.com/v1/create-qr-code/?size=80x80&data=https://wa.me/viva1a" alt="QR" className="w-16 h-16 rounded-lg bg-slate-100" />
                       <p className="text-sm text-slate-500">Escanea para hablar con soporte técnico</p>
                     </div>
                   ) : (
                     <div className="space-y-2">
                       <p className="text-sm text-slate-600 flex justify-between"><span>Usuario:</span> <span className="font-mono font-bold text-slate-900">{item.user}</span></p>
                       <p className="text-sm text-slate-600 flex justify-between"><span>Pass:</span> <span className="font-mono font-bold text-slate-900">{item.pass}</span></p>
                     </div>
                   )}
                </div>
              ))}
            </motion.div>
          )}
        </AnimatePresence>

        {/* Grid de Resultados */}
        <div className="space-y-12">
          {categories.map(cat => {
            const items = displayedLinks.filter(l => l.category === cat);
            if (items.length === 0) return null;
            return (
              <section key={cat}>
                <h3 className="text-sm font-bold uppercase tracking-widest text-slate-400 mb-6 flex items-center gap-3">
                  {cat}
                  <div className="h-px flex-1 bg-slate-200"></div>
                </h3>
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                  {items.map(link => (
                    <motion.a
                      key={link.id}
                      href={link.url}
                      target="_blank"
                      rel="noopener noreferrer"
                      layout
                      initial={{ opacity: 0, scale: 0.95 }}
                      animate={{ opacity: 1, scale: 1 }}
                      whileHover={{ y: -5 }}
                      className="group block bg-white border border-slate-200 p-6 rounded-2xl hover:border-blue-400 hover:shadow-xl hover:shadow-blue-500/10 transition-all duration-300"
                    >
                      <div className="flex justify-between items-start mb-4">
                        <div className="p-3 bg-slate-50 group-hover:bg-blue-50 rounded-xl transition-colors">
                          <CategoryIcon category={link.category} />
                        </div>
                        <div className="text-slate-300 group-hover:text-blue-500 transition-colors">
                          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14" /></svg>
                        </div>
                      </div>
                      <h4 className="text-lg font-bold text-slate-800 mb-2 group-hover:text-blue-700 transition-colors">{link.name}</h4>
                      <p className="text-sm text-slate-500 leading-relaxed">{link.description}</p>
                    </motion.a>
                  ))}
                </div>
              </section>
            );
          })}
        </div>

        {displayedLinks.length === 0 && (
          <div className="py-20 text-center">
            <div className="w-20 h-20 bg-slate-100 rounded-full flex items-center justify-center mx-auto mb-6">
              <svg className="w-10 h-10 text-slate-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9.172 9.172a4 4 0 015.656 0M9 10h.01M15 10h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
            </div>
            <h3 className="text-xl font-bold text-slate-800">No encontramos nada similar</h3>
            <p className="text-slate-500 mt-2">Intenta usar otras palabras o revisa la ortografía.</p>
            <button 
              onClick={() => { setQuery(''); setFilteredIds(MEDICAL_LINKS.map(l => l.id)); }}
              className="mt-6 px-6 py-2 bg-slate-200 hover:bg-slate-300 rounded-full font-bold text-slate-700 transition-colors"
            >
              Ver todos los enlaces
            </button>
          </div>
        )}
      </main>

      <footer className="mt-20 py-12 border-t border-slate-200 bg-white">
        <div className="max-w-7xl mx-auto px-6 flex flex-col md:flex-row justify-between items-center gap-6">
          <div className="text-slate-400 text-sm">
            © 2024 Viva1A IPS • Gestión Hospitalaria Inteligente
          </div>
          <div className="flex gap-8">
            <span className="text-xs font-bold text-blue-600/50 uppercase tracking-widest">Daniel Ruano</span>
            <span className="text-xs font-bold text-slate-400 uppercase tracking-widest">Soporte IT v2.5</span>
          </div>
        </div>
      </footer>
    </div>
  );
};

// Componente para iconos por categoría
const CategoryIcon = ({ category }: { category: string }) => {
  switch (category) {
    case 'Clínico':
      return <svg className="w-6 h-6 text-blue-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>;
    case 'Resultados':
      return <svg className="w-6 h-6 text-cyan-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" /></svg>;
    case 'Administrativo':
      return <svg className="w-6 h-6 text-indigo-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>;
    case 'Soporte':
      return <svg className="w-6 h-6 text-emerald-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M18.364 5.636l-3.536 3.536m0 5.656l3.536 3.536M9.172 9.172L5.636 5.636m3.536 9.192l-3.536 3.536M21 12a9 9 0 11-18 0 9 9 0 0118 0zm-5 0a4 4 0 11-8 0 4 4 0 018 0z" /></svg>;
    default:
      return <svg className="w-6 h-6 text-slate-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13.828 10.172a4 4 0 00-5.656 0l-4 4a4 4 0 105.656 5.656l1.102-1.101m-.758-4.899a4 4 0 005.656 0l4-4a4 4 0 00-5.656-5.656l-1.1 1.1" /></svg>;
  }
};

const container = document.getElementById('root');
const root = createRoot(container!);
root.render(<App />);

