const getCatColor = (cat: string) => {
  switch (cat) {
    case 'Clínico': return 'text-blue-600';
    case 'Resultados': return 'text-cyan-600';
    case 'Administrativo': return 'text-indigo-600';
    case 'Soporte': return 'text-emerald-600';
    default: return 'text-slate-600';
  }
};

const CategoryIcon = ({ category, small, active }: { category: string, small?: boolean, active?: boolean }) => {
  const size = small ? "w-4 h-4" : "w-6 h-6";
  const color = active ? "text-white" : getCatColor(category);

  switch (category) {
    case 'Clínico':
      return <svg className={`${size} ${color}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>;
