            {categories.map(cat => (
              <button
                key={cat}
                onClick={() => handleCategoryClick(cat)}
                className={`flex items-center gap-2 px-5 py-2 rounded-xl transition-all text-xs font-bold border-2 ${
                  activeCategory === cat 
                    ? `${getCatBgActive(cat)} text-white border-transparent shadow-md` 
                    : `bg-white text-slate-600 border-slate-100 hover:border-slate-300 hover:bg-slate-50`
