// Helpers de Color
const getCatColor = (cat: string) => {
  switch (cat) {
    case 'Clínico': return 'text-blue-600';
    case 'Resultados': return 'text-cyan-500';
    case 'Administrativo': return 'text-indigo-600';
    case 'Soporte': return 'text-emerald-500';
    default: return 'text-slate-600';
  }
};

const getCatBg = (cat: string) => {
  switch (cat) {
    case 'Clínico': return 'bg-blue-600';
    case 'Resultados': return 'bg-cyan-500';
    case 'Administrativo': return 'bg-indigo-600';
    case 'Soporte': return 'bg-emerald-500';
    default: return 'bg-slate-600';
  }
};

const getCatBgActive = (cat: string) => {
  switch (cat) {
    case 'Clínico': return 'bg-blue-600 hover:bg-blue-700';
    case 'Resultados': return 'bg-cyan-500 hover:bg-cyan-600';
    case 'Administrativo': return 'bg-indigo-600 hover:bg-indigo-700';
    case 'Soporte': return 'bg-emerald-500 hover:bg-emerald-600';
    default: return 'bg-slate-600 hover:bg-slate-700';
  }
};

const getCatBorder = (cat: string) => {
  switch (cat) {
    case 'Clínico': return 'border-blue-500';
    case 'Resultados': return 'border-cyan-400';
    case 'Administrativo': return 'border-indigo-500';
    case 'Soporte': return 'border-emerald-400';
    default: return 'border-slate-300';
  }
};

const CategoryIcon = ({ category, small, active }: { category: string, small?: boolean, active?: boolean }) => {
