// Helpers de Color
const getCatColor = (cat: string) => {
  switch (cat) {
    case 'Clínico': return 'text-blue-600';
    case 'Resultados': return 'text-cyan-500';
    case 'Administrativo': return 'text-indigo-600';
    case 'Soporte': return 'text-emerald-500';
    default: return 'text-slate-600';
  }
};

const getCatBg = (cat: string) => {
  switch (cat) {
    case 'Clínico': return 'bg-blue-600';
    case 'Resultados': return 'bg-cyan-500';
    case 'Administrativo': return 'bg-indigo-600';
    case 'Soporte': return 'bg-emerald-500';
    default: return 'bg-slate-600';
  }
};

const getCatBgActive = (cat: string) => {
  switch (cat) {
    case 'Clínico': return 'bg-blue-600 hover:bg-blue-700 shadow-blue-200';
    case 'Resultados': return 'bg-cyan-500 hover:bg-cyan-600 shadow-cyan-200';
    case 'Administrativo': return 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-200';
    case 'Soporte': return 'bg-emerald-500 hover:bg-emerald-600 shadow-emerald-200';
    default: return 'bg-slate-700 hover:bg-slate-800';
  }
};

