// Helpers de Color
const getCatColor = (cat: string) => {
  switch (cat) {
    case 'Clínico': return 'text-blue-600';
    case 'Resultados': return 'text-cyan-500';
    case 'Administrativo': return 'text-indigo-600';
    case 'Soporte': return 'text-emerald-500';
    default: return 'text-slate-600';
  }
};

const getCatBg = (cat: string) => {
  switch (cat) {
    case 'Clínico': return 'bg-blue-600';
    case 'Resultados': return 'bg-cyan-500';
    case 'Administrativo': return 'bg-indigo-600';
    case 'Soporte': return 'bg-emerald-500';
    default: return 'bg-slate-600';
  }
};

const getCatBgActive = (cat: string) => {
  switch (cat) {
    case 'Clínico': return 'bg-blue-600 hover:bg-blue-700 shadow-blue-200';
    case 'Resultados': return 'bg-cyan-500 hover:bg-cyan-600 shadow-cyan-200';
    case 'Administrativo': return 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-200';
    case 'Soporte': return 'bg-emerald-500 hover:bg-emerald-600 shadow-emerald-200';
    default: return 'bg-slate-700 hover:bg-slate-800';
  }
};

const CategoryIcon = ({ category, medium, small, active }: { category: string, medium?: boolean, small?: boolean, active?: boolean }) => {
  const size = small ? "w-4 h-4" : (medium ? "w-5 h-5" : "w-6 h-6");
  const color = active ? "text-white" : getCatColor(category);

  switch (category) {
    case 'Clínico':
      return <svg className={`${size} ${color}`} fill="currentColor" viewBox="0 0 24 24"><path d="M19 3H5c-1.1 0-2 .9-2 2v14c0 1.1.9 2 2 2h14c1.1 0 2-.9 2-2V5c0-1.1-.9-2-2-2zm-1 11h-4v4h-4v-4H6v-4h4V6h4v4h4v4z"/></svg>;
    case 'Resultados':
      return <svg className={`${size} ${color}`} fill="currentColor" viewBox="0 0 24 24"><path d="M19 3H5c-1.1 0-2 .9-2 2v14c0 1.1.9 2 2 2h14c1.1 0 2-.9 2-2V5c0-1.1-.9-2-2-2zM9 17H7v-7h2v7zm4 0h-2V7h2v10zm4 0h-2v-4h2v4z"/></svg>;
    case 'Administrativo':
      return <svg className={`${size} ${color}`} fill="currentColor" viewBox="0 0 24 24"><path d="M11.99 2C6.47 2 2 6.48 2 12s4.47 10 9.99 10C17.52 22 22 17.52 22 12S17.52 2  11.99 2zM12 20c-4.42 0-8-3.58-8-8s3.58-8 8-8 8 3.58 8 8-3.58 8-8 8zm.5-13H11v6l5.25 3.15.75-1.23-4.5-2.67z"/></svg>;
    case 'Soporte':
      return <svg className={`${size} ${color}`} fill="currentColor" viewBox="0 0 24 24"><path d="M12 1L3 5v6c0 5.55 3.84 10.74 9 12 5.16-1.26 9-6.45 9-12V5l-9-4zm-1 14l-4-4 1.41-1.41L11 12.17l4.59-4.59L17 9l-6 6z"/></svg>;
    default:
