            </div>

            {/* Barra de Búsqueda Integrada */}
            <form onSubmit={handleSearch} className="relative group flex-1 max-w-[300px]">
              <div className="absolute -inset-0.5 bg-gradient-to-r from-[#0077b6] to-indigo-500 rounded-xl blur opacity-10 group-focus-within:opacity-25 transition duration-500"></div>
              <div className="relative flex items-center bg-slate-100 border border-slate-200 rounded-xl p-0.5 transition-all focus-within:bg-white focus-within:border-[#0077b6]">
