// Helpers de Color
const getCatBg = (cat: string) => {
  switch (cat) {
    case 'Asistenciales': return 'bg-[#0077b6]';
    case 'Operativos': return 'bg-[#475569]';
    case 'Capacitación': return 'bg-indigo-600';
    case 'Soporte': return 'bg-emerald-600';
    default: return 'bg-slate-600';
  }
};

const getCatBgActive = (cat: string) => {
  switch (cat) {
    case 'Asistenciales': return 'bg-[#0077b6] hover:bg-[#005f91] shadow-blue-200';
    case 'Operativos': return 'bg-[#334155] hover:bg-[#1e293b] shadow-slate-200';
    case 'Capacitación': return 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-200';
    case 'Soporte': return 'bg-emerald-600 hover:bg-emerald-700 shadow-emerald-200';
    default: return 'bg-slate-700 hover:bg-slate-800';
  }
};

const CategoryIcon = ({ type, active, small }: { type: string, active?: boolean, small?: boolean }) => {
  const size = small ? "w-4 h-4" : "w-5 h-5";
