// --- Componente de Credencial con Copiado ---
const CredentialItem = ({ label, value }: { label: string; value: string }) => {
  const [copied, setCopied] = useState(false);

  const handleCopy = () => {
    navigator.clipboard.writeText(value);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="flex justify-between items-center bg-slate-50 p-3 rounded-2xl border border-slate-100 hover:bg-blue-50 transition-all group/item relative">
      <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{label}</span>
      <div className="flex items-center gap-2">
        <span className="font-mono font-bold text-slate-900 text-sm">{value}</span>
        <button 
          onClick={handleCopy}
          className={`p-1.5 rounded-lg transition-all ${copied ? 'bg-emerald-500 text-white' : 'bg-white text-slate-400 hover:text-blue-600 shadow-sm border border-slate-100'}`}
          title="Copiar al portapapeles"
        >
          {copied ? (
            <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7" /></svg>
          ) : (
            <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M8 16H6a2 2 0 01-2-2V6a2 2 0 012-2h8a2 2 0 012 2v2m-6 12h8a2 2 0 002-2v-8a2 2 0 00-2-2h-8a2 2 0 00-2 2v8a2 2 0 002 2z" /></svg>
          )}
        </button>
      </div>
      <AnimatePresence>
        {copied && (
          <motion.span 
            initial={{ opacity: 0, y: 5 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0 }}
            className="absolute -top-6 right-0 text-[9px] font-bold text-emerald-600 bg-emerald-50 px-2 py-0.5 rounded-full border border-emerald-100"
          >
            ¡Copiado!
          </motion.span>
        )}
      </AnimatePresence>
    </div>
  );
};

const App = () => {
  const [query, setQuery] = useState('');
  const [filteredIds, setFilteredIds] = useState<string[]>(MEDICAL_LINKS.map(l => l.id));
  const [activeCategory, setActiveCategory] = useState<string | null>(null);
  const [isAiLoading, setIsAiLoading] = useState(false);

  const categories = ['Asistenciales', 'Operativos', 'Capacitación', 'Soporte'];

  const handleSearch = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    setActiveCategory(null);

    if (!query.trim()) {
      setFilteredIds(MEDICAL_LINKS.map(l => l.id));
      return;
    }

    setIsAiLoading(true);
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

    try {
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `Filtra estos enlaces para un médico: "${query}". Retorna un JSON con solo los IDs.
        Enlaces: ${JSON.stringify(MEDICAL_LINKS.map(l => ({ id: l.id, name: l.name, description: l.description, keywords: l.keywords })))}`,
        config: {
          responseMimeType: "application/json",
          responseSchema: { type: Type.ARRAY, items: { type: Type.STRING } }
        }
      });
      const resultIds = JSON.parse(response.text || '[]');
      setFilteredIds(resultIds.length > 0 ? resultIds : MEDICAL_LINKS.filter(l => l.name.toLowerCase().includes(query.toLowerCase())).map(l => l.id));
    } catch (err) {
      setFilteredIds(MEDICAL_LINKS.filter(l => l.name.toLowerCase().includes(query.toLowerCase())).map(l => l.id));
    } finally {
      setIsAiLoading(false);
    }
  };

  const handleCategoryClick = (cat: string | null) => {
    setQuery('');
    if (activeCategory === cat) {
      setActiveCategory(null);
      setFilteredIds(MEDICAL_LINKS.map(l => l.id));
    } else {
      setActiveCategory(cat);
      if (cat === null) {
        setFilteredIds(MEDICAL_LINKS.map(l => l.id));
      } else {
        setFilteredIds(MEDICAL_LINKS.filter(l => l.category === cat).map(l => l.id));
      }
    }
  };

  const displayedLinks = MEDICAL_LINKS.filter(l => filteredIds.includes(l.id));

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 font-sans flex flex-col relative overflow-hidden">
