}

.search-box {
    display: flex;
    align-items: center;
    background: #f1f5f9;
    border: 1px solid var(--border-color);
    border-radius: 12px;
    padding: 4px;
    transition: all 0.3s;
}

.search-box:focus-within {
    background: white;
    border-color: var(--primary);
