// --- Componentes ---
const CopyRow = ({ label, value }: { label: string, value: string }) => {
  const [copied, setCopied] = useState(false);
  const handleCopy = () => {
    navigator.clipboard.writeText(value);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };
  return (
    <div className="row-copy">
      <span className="row-label">{label}</span>
      <span className="row-val">{value}</span>
      <button className="row-btn" onClick={handleCopy}>
        {copied ? '✓' : '⧉'}
      </button>
    </div>
  );
};

const App = () => {
  const [query, setQuery] = useState('');
  const [filteredIds, setFilteredIds] = useState<string[]>(MEDICAL_LINKS.map(l => l.id));
  const [activeCat, setActiveCat] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  const categories = ['Asistenciales', 'Operativos', 'Capacitación', 'Soporte'];

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!query.trim()) {
      setFilteredIds(MEDICAL_LINKS.map(l => l.id));
      return;
    }

    setLoading(true);
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    try {
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `Analiza esta consulta médica: "${query}". Retorna un array JSON con los IDs de los enlaces médicos relevantes.
        Enlaces: ${JSON.stringify(MEDICAL_LINKS.map(l => ({ id: l.id, name: l.name, desc: l.description })))}`,
        config: {
          responseMimeType: "application/json",
          responseSchema: { type: Type.ARRAY, items: { type: Type.STRING } }
        }
      });
      const ids = JSON.parse(response.text || '[]');
      setFilteredIds(ids.length > 0 ? ids : MEDICAL_LINKS.filter(l => l.name.toLowerCase().includes(query.toLowerCase())).map(l => l.id));
    } catch (err) {
      setFilteredIds(MEDICAL_LINKS.filter(l => l.name.toLowerCase().includes(query.toLowerCase())).map(l => l.id));
    } finally {
      setLoading(false);
    }
  };

  const selectCat = (cat: string | null) => {
    setActiveCat(cat);
    setQuery('');
    if (cat === null) setFilteredIds(MEDICAL_LINKS.map(l => l.id));
    else setFilteredIds(MEDICAL_LINKS.filter(l => l.category === cat).map(l => l.id));
  };

  return (
    <div className="app-wrapper">
      <nav className="navbar">
        <div className="nav-inner">
          <div className="logo-group">
            <div className="logo-box">V1</div>
            <div className="logo-text">VIVA1A <span>PORTAL</span></div>
          </div>

          <form className="search-wrapper" onSubmit={handleSearch}>
            <div className="search-bar">
              <input 
                type="text" 
                className="search-input" 
                placeholder="Busca por función o nombre..." 
                value={query}
                onChange={(e) => setQuery(e.target.value)}
              />
              <button type="submit" className="ai-button" disabled={loading}>
                {loading ? 'BUSCANDO...' : 'IA SEARCH'}
              </button>
            </div>
          </form>

          <div className="category-nav">
            <button 
              className={`category-btn ${activeCat === null ? 'active' : ''}`}
              onClick={() => selectCat(null)}
            >Todos</button>
            {categories.map(cat => (
              <button 
                key={cat} 
                className={`category-btn ${activeCat === cat ? 'active' : ''}`}
                onClick={() => selectCat(cat)}
              >{cat}</button>
            ))}
          </div>
        </div>
      </nav>

      <div className="layout-container">
        <main className="main-content">
          <header className="header-section">
            <h1 className="header-title">Mesa de <span>Herramientas</span></h1>
            <p className="header-desc">Gestión integral para profesionales de salud IPS Viva1A.</p>
          </header>

          <div className="links-grid">
            <AnimatePresence mode="popLayout">
              {MEDICAL_LINKS.filter(l => filteredIds.includes(l.id)).map((link) => (
                <motion.a
                  key={link.id}
                  href={link.url}
                  target="_blank"
                  rel="noopener noreferrer"
                  layout
                  initial={{ opacity: 0, scale: 0.95 }}
                  animate={{ opacity: 1, scale: 1 }}
                  exit={{ opacity: 0, scale: 0.9 }}
                  className="card"
                  style={{ '--accent-color': getCatColor(link.category) } as any}
                >
                  <div className="card-accent"></div>
                  <div className="card-icon">🩺</div>
                  <h3 className="card-name">{link.name}</h3>
                  <p className="card-desc">{link.description}</p>
                  <div>
                    <span className="card-tag">{link.category}</span>
                  </div>
                </motion.a>
              ))}
            </AnimatePresence>
          </div>
        </main>

        <aside className="sidebar">
          <div className="support-card">
            <h2 style={{fontSize: '2rem', fontWeight: 900, marginBottom: '0.5rem'}}>Soporte TI</h2>
            <p style={{fontSize: '0.9rem', opacity: 0.9}}>¿Necesitas ayuda con tu usuario o PC?</p>
            <a href="https://wa.me/xxx" className="wa-btn">
              <span>WhatsApp Soporte</span>
            </a>
          </div>

          <div className="cred-list">
            <h3 style={{fontSize: '0.7rem', fontWeight: 900, letterSpacing: '0.2em', color: 'var(--text-muted)', marginBottom: '0.5rem'}}>CREDENCIALES GENERALES</h3>
            {CREDENTIALS.map(cred => (
              <div key={cred.name} className="cred-card" style={{'--c-color': cred.color} as any}>
                <div className="cred-head">
                  <span>{cred.icon}</span>
                  <span>{cred.name}</span>
                </div>
                <CopyRow label="Usuario" value={cred.user} />
                <CopyRow label="Clave" value={cred.pass} />
              </div>
            ))}
          </div>
        </aside>
      </div>

      <footer className="footer">
        <span>Portal de Gestión Médica IPS Viva1A</span>
        <span style={{color: 'var(--primary)'}}>Daniel Ruano</span>
      </footer>
    </div>
  );
};

const getCatColor = (cat: string) => {
  switch (cat) {
    case 'Asistenciales': return '#0077b6';
    case 'Operativos': return '#475569';
    case 'Capacitación': return '#4f46e5';
    case 'Soporte': return '#10b981';
    default: return '#ccc';
  }
};

const container = document.getElementById('root');
const root = createRoot(container!);
root.render(<App />);

