  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.1em;
}

/* Main Layout */
.app-layout {
  display: flex;
  min-height: calc(100vh - 72px);
}

.content-area {
  flex: 1;
  padding: 2.5rem 3rem;
  max-width: 1700px;
  margin: 0 auto;
}

.page-header {
  margin-bottom: 2.5rem;
}

.page-title {
  font-family: var(--font-display);
  font-size: 2rem;
  font-weight: 800;
  margin-bottom: 0.5rem;
}

.page-title span { color: var(--primary); }

.page-desc {
  color: var(--text-muted);
  font-weight: 500;
}

/* Cards Grid */
.cards-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(320px, 1fr));
  gap: 1.5rem;
  padding-bottom: 5rem;
}

.link-card {
  background: white;
  border: 1px solid var(--border);
  border-radius: var(--radius-xl);
  padding: 2rem;
  text-decoration: none;
  color: inherit;
  display: flex;
  flex-direction: column;
  position: relative;
  overflow: hidden;
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
}

.link-card:hover {
  transform: translateY(-8px);
  box-shadow: var(--shadow-xl);
  border-color: rgba(0, 119, 182, 0.2);
}

.card-accent {
  position: absolute;
  top: 0;
  left: 0;
  width: 6px;
  height: 100%;
  background: var(--cat-color);
  opacity: 0.1;
  transition: opacity 0.3s;
}

.link-card:hover .card-accent { opacity: 1; }

.card-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 1.5rem;
}

.card-icon-box {
  width: 54px;
  height: 54px;
  background: #f8fafc;
  border-radius: 16px;
  display: flex;
  align-items: center;
  justify-content: center;
}

.arrow-circle {
  width: 44px;
  height: 44px;
  background: #f8fafc;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  color: #cbd5e1;
