// --- Componentes ---
const CategoryIcon = ({ type }: { type: string }) => {
  switch (type) {
    case 'Todos': return <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M13 2L3 14h9l-1 8 10-12h-9l1-8z"/></svg>;
