import React, { useState } from 'react';
import { createRoot } from 'react-dom/client';
import { GoogleGenAI, Type } from "@google/genai";
import { motion, AnimatePresence } from "framer-motion";

// --- Tipos ---
type CategoryType = 'Asistenciales' | 'Operativos' | 'Capacitación' | 'Soporte';

interface MedicalLink {
  id: string;
  name: string;
  url: string;
  category: CategoryType;
  description: string;
}

// --- Datos ---
const MEDICAL_LINKS: MedicalLink[] = [
  { id: 'everest', name: 'EVEREST', url: 'https://appportal.everestintelligent.com/EverHealth/', category: 'Asistenciales', description: 'Portal principal de gestión de salud EverHealth.' },
  { id: 'pana', name: 'PANA', url: 'https://nuevaeps.viva1a.com.co/pana/', category: 'Asistenciales', description: 'Sistema de gestión Nueva EPS.' },
  { id: 'digiturno', name: 'DIGITURNO', url: 'http://api.digiturno.viva1a.com.co:85/', category: 'Operativos', description: 'Gestión de turnos y filas en sala.' },
  { id: 'mipres', name: 'MIPRES', url: 'https://mipres.sispro.gov.co/MIPRESNOPBS/Login.aspx?ReturnUrl=%2fMIPRESNOPBS', category: 'Asistenciales', description: 'Prescripción de servicios y tecnologías no PBS.' },
  { id: 'fichas', name: 'FICHAS EPIDEMIOLÓGICAS', url: 'https://drive.google.com/drive/folders/1DHFZPwH_ZaG5NUTu0NmPYtfmV3ZZTybv?usp=share_link', category: 'Soporte', description: 'Formatos para reporte de eventos en salud pública.' },
  { id: 'lumier', name: 'LUMIER', url: 'https://lumierdigital.com:8443/login.lu', category: 'Asistenciales', description: 'Visualizador de imágenes diagnósticas y rayos X.' },
  { id: 'annarlytics', name: 'ANNARLYTICS', url: 'http://datacare.viva1a.com.co/datacare/#nbb', category: 'Asistenciales', description: 'Resultados de laboratorio clínico centralizado.' },
  { id: 'athenea', name: 'ATHENEA', url: 'https://medicosviva1a.atheneasoluciones.com/', category: 'Asistenciales', description: 'Sistema alterno de resultados médicos.' },
  { id: 'agenda_lab', name: 'AGENDA LABORATORIOS', url: 'https://appcita.viva1a.com.co:8051/laboratorio/agente', category: 'Operativos', description: 'Programación de citas para toma de muestras.' },
  { id: 'glpi', name: 'MESA DE SERVICIO (GLPI)', url: 'http://mesadeservicios.viva1a.com.co/glpi/index.php', category: 'Soporte', description: 'Reporte de fallas técnicas y soporte IT.' },
  { id: 'viva_aprendiendo', name: 'VIVA APRENDIENDO', url: 'http://vivaaprendiendo.com.co/', category: 'Capacitación', description: 'Plataforma de capacitación continua.' },
  { id: 'mi_portal', name: 'MI PORTAL GH', url: 'https://www.miportalgh.com/', category: 'Operativos', description: 'Gestión humana y desprendibles de nómina.' },
];

const CREDENTIALS = [
  { name: 'MESA DE SERVICIO', user: 'MEDICOS.CRA80', pass: 'VIVA2023', icon: '🖥️', color: '#4d69ff' },
  { name: 'ATHENEA', user: 'CONSULTAMED', pass: 'Viva1a*md04', icon: '📋', color: '#a855f7' },
];

// --- Iconos ---
const CategoryIcon = ({ type }: { type: string }) => {
  switch (type) {
    case 'Todos': return <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M13 2L3 14h9l-1 8 10-12h-9l1-8z" fill="currentColor"/></svg>;
    case 'Asistenciales': return <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/><polyline points="14 2 14 8 20 8"/><line x1="16" y1="13" x2="8" y2="13"/><line x1="16" y1="17" x2="8" y2="17"/><polyline points="10 9 9 9 8 9"/></svg>;
    case 'Operativos': return <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><ellipse cx="12" cy="5" rx="9" ry="3"/><path d="M21 12c0 1.66-4 3-9 3s-9-1.34-9-3"/><path d="M3 5v14c0 1.66 4 3 9 3s9-1.34 9-3V5"/></svg>;
    case 'Capacitación': return <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M22 10v6M2 10l10-5 10 5-10 5z"/><path d="M6 12v5c3 3 9 3 12 0v-5"/></svg>;
    case 'Soporte': return <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><circle cx="12" cy="12" r="10"/><circle cx="12" cy="12" r="4"/><line x1="4.93" y1="4.93" x2="9.17" y2="9.17"/><line x1="14.83" y1="14.83" x2="19.07" y2="19.07"/><line x1="14.83" y1="9.17" x2="19.07" y2="4.93"/><line x1="4.93" y1="19.07" x2="9.17" y2="14.83"/></svg>;
    default: return null;
  }
};

const App = () => {
  const [query, setQuery] = useState('');
  const [activeCategory, setActiveCategory] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [filteredIds, setFilteredIds] = useState<string[]>(MEDICAL_LINKS.map(l => l.id));

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!query.trim()) {
      setFilteredIds(MEDICAL_LINKS.map(l => l.id));
      return;
    }
    setLoading(true);
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `Filter these medical link IDs for query: "${query}". Return a JSON array of IDs. Enlaces: ${JSON.stringify(MEDICAL_LINKS.map(l => ({id: l.id, name: l.name, desc: l.description})))}`,
        config: {
          responseMimeType: "application/json",
          responseSchema: { type: Type.ARRAY, items: { type: Type.STRING } }
        }
      });
      const ids = JSON.parse(response.text || '[]');
      setFilteredIds(ids.length > 0 ? ids : MEDICAL_LINKS.filter(l => l.name.toLowerCase().includes(query.toLowerCase())).map(l => l.id));
    } catch (err) {
      setFilteredIds(MEDICAL_LINKS.filter(l => l.name.toLowerCase().includes(query.toLowerCase())).map(l => l.id));
    } finally {
      setLoading(false);
    }
  };

  const handleCatSelect = (cat: string | null) => {
    setActiveCategory(cat);
    setQuery('');
    if (cat === null) setFilteredIds(MEDICAL_LINKS.map(l => l.id));
    else setFilteredIds(MEDICAL_LINKS.filter(l => l.category === cat).map(l => l.id));
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
  };

  return (
    <div className="app-root">
      <nav className="navbar">
        <div className="nav-container">
          <div className="brand">
            <div className="brand-logo">
              <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M3 21h18M3 7v1a3 3 0 0 0 6 0V4m0 4v1a3 3 0 0 0 6 0V4m0 4v1a3 3 0 0 0 6 0V4M9 21V4M15 21V4"/></svg>
            </div>
            <div className="brand-text">VIVA1A <span>PORTAL</span></div>
          </div>

          <form className="search-box" onSubmit={handleSearch}>
            <input 
              type="text" 
              className="search-input" 
              placeholder="Buscar..." 
              value={query}
              onChange={(e) => setQuery(e.target.value)}
            />
            <button type="submit" className="ia-btn" disabled={loading}>
              {loading ? '...' : 'IA'}
            </button>
          </form>

          <div className="filters-bar">
            <button 
              className={`filter-btn ${activeCategory === null ? 'active' : ''}`}
              onClick={() => handleCatSelect(null)}
            >
              <CategoryIcon type="Todos" />
              <span>Todos</span>
            </button>
            <button className={`filter-btn ${activeCategory === 'Asistenciales' ? 'active' : ''}`} onClick={() => handleCatSelect('Asistenciales')}>
              <CategoryIcon type="Asistenciales" />
              <span>Asistenciales</span>
            </button>
            <button className={`filter-btn ${activeCategory === 'Operativos' ? 'active' : ''}`} onClick={() => handleCatSelect('Operativos')}>
              <CategoryIcon type="Operativos" />
              <span>Operativos</span>
            </button>
            <button className={`filter-btn ${activeCategory === 'Capacitación' ? 'active' : ''}`} onClick={() => handleCatSelect('Capacitación')}>
              <CategoryIcon type="Capacitación" />
              <span>Capacitación</span>
            </button>
            <button className={`filter-btn ${activeCategory === 'Soporte' ? 'active' : ''}`} onClick={() => handleCatSelect('Soporte')}>
              <CategoryIcon type="Soporte" />
              <span>Soporte</span>
            </button>
          </div>

          <div className="badge-version">ESPECIALISTA V4.12</div>
        </div>
      </nav>

      <div className="app-layout">
        <main className="content-area">
          <header className="page-header">
            <h1 className="page-title">Portal de <span>Herramientas</span></h1>
            <p className="page-desc">Acceso directo a las plataformas operativas de la IPS.</p>
          </header>

          <div className="cards-grid">
            <AnimatePresence mode="popLayout">
              {MEDICAL_LINKS.filter(l => filteredIds.includes(l.id)).map((link) => (
                <motion.a
                  key={link.id}
                  href={link.url}
                  target="_blank"
                  rel="noopener noreferrer"
                  layout
                  initial={{ opacity: 0, y: 10 }}
                  animate={{ opacity: 1, y: 0 }}
                  exit={{ opacity: 0, scale: 0.95 }}
                  className="link-card"
                >
                  <div className="card-header">
                    <div className="card-icon-box">
                      <CategoryIcon type={link.category} />
                    </div>
                    <div className="arrow-circle">→</div>
                  </div>
                  <div className="card-body">
                    <h4>{link.name}</h4>
                    <p>{link.description}</p>
                  </div>
                  <div className="card-footer">
                    <span className="tag-cat">{link.category}</span>
                  </div>
                </motion.a>
              ))}
            </AnimatePresence>
          </div>
        </main>

        <aside className="sidebar">
          <div className="soporte-card">
            <div className="soporte-icon">
              <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M21 11.5a8.38 8.38 0 0 1-.9 3.8 8.5 8.5 0 1 1-7.6-11.7 8.38 8.38 0 0 1 3.8.9L21 3z"/></svg>
            </div>
            <h2 className="soporte-title">Soporte TI</h2>
            <p className="soporte-desc">Atención inmediata para problemas técnicos, bloqueos de usuario o fallos de sistema.</p>
            <a href="#" className="wa-btn">
              <svg width="18" height="18" viewBox="0 0 24 24" fill="currentColor"><path d="M17.472 14.382c-.297-.149-1.758-.867-2.03-.967-.273-.099-.471-.148-.67.15-.197.297-.767.966-.94 1.164-.173.199-.347.223-.644.075-.297-.15-1.255-.463-2.39-1.475-.883-.788-1.48-1.761-1.653-2.059-.173-.297-.018-.458.13-.606.134-.133.298-.347.446-.52.149-.174.198-.298.298-.497.099-.198.05-.371-.025-.52-.075-.149-.669-1.612-.916-2.207-.242-.579-.487-.5-.669-.51-.173-.008-.371-.01-.57-.01-.198 0-.52.074-.792.372-.272.297-1.04 1.016-1.04 2.479 0 1.462 1.065 2.875 1.213 3.074.149.198 2.096 3.2 5.077 4.487.709.306 1.262.489 1.694.625.712.227 1.36.195 1.871.118.571-.085 1.758-.719 2.006-1.413.248-.694.248-1.289.173-1.413-.074-.124-.272-.198-.57-.347m-5.421 7.403h-.004a9.87 9.87 0 01-5.031-1.378l-.361-.214-3.741.982.998-3.648-.235-.374a9.86 9.86 0 01-1.51-5.26c.001-5.45 4.436-9.884 9.888-9.884 2.64 0 5.122 1.03 6.988 2.898a9.825 9.825 0 012.893 6.994c-.003 5.45-4.437 9.884-9.885 9.884m8.413-18.297A11.815 11.815 0 0012.05 0C5.495 0 .16 5.335.157 11.892c0 2.096.547 4.142 1.588 5.945L0 24l6.335-1.662c1.72.937 3.659 1.431 5.63 1.432h.005c6.554 0 11.89-5.335 11.893-11.893a11.821 11.821 0 00-3.48-8.413Z"/></svg>
              SOPORTE WHATSAPP
            </a>
            <a href="http://mesadeservicios.viva1a.com.co/glpi/index.php" className="glpi-link">MESA DE SERVICIO GLPI</a>
          </div>

          <div className="cred-section">
            <div className="cred-section-title">CREDENCIALES</div>
            {CREDENTIALS.map(cred => (
              <div key={cred.name} className="cred-card" style={{ '--accent-color': cred.color } as any}>
