];

const CREDENTIALS = [
  { name: 'MESA DE SERVICIO', user: 'MEDICOS.CRA80', pass: 'VIVA2023', icon: '🖥️', color: '#4d69ff' },
  { name: 'ATHENEA', user: 'CONSULTAMED', pass: 'Viva1a*md04', icon: '📋', color: '#a855f7' },
];

// --- Iconos ---
const CategoryIcon = ({ type }: { type: string }) => {
  const iconProps = { viewBox: "0 0 24 24", fill: "none", stroke: "currentColor", strokeWidth: "2" };
  switch (type) {
    case 'Todos': return <svg {...iconProps} strokeWidth="2.5"><path d="M13 2L3 14h9l-1 8 10-12h-9l1-8z" fill="currentColor"/></svg>;
    case 'Asistenciales': return <svg {...iconProps}><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/><polyline points="14 2 14 8 20 8"/><line x1="16" y1="13" x2="8" y2="13"/><line x1="16" y1="17" x2="8" y2="17"/><polyline points="10 9 9 9 8 9"/></svg>;
    case 'Operativos': return <svg {...iconProps}><ellipse cx="12" cy="5" rx="9" ry="3"/><path d="M21 12c0 1.66-4 3-9 3s-9-1.34-9-3"/><path d="M3 5v14c0 1.66 4 3 9 3s9-1.34 9-3V5"/></svg>;
    case 'Capacitación': return <svg {...iconProps}><path d="M22 10v6M2 10l10-5 10 5-10 5z"/><path d="M6 12v5c3 3 9 3 12 0v-5"/></svg>;
    case 'Soporte': return <svg {...iconProps}><circle cx="12" cy="12" r="10"/><circle cx="12" cy="12" r="4"/><line x1="4.93" y1="4.93" x2="9.17" y2="9.17"/><line x1="14.83" y1="14.83" x2="19.07" y2="19.07"/><line x1="14.83" y1="9.17" x2="19.07" y2="4.93"/><line x1="4.93" y1="19.07" x2="9.17" y2="14.83"/></svg>;
    default: return null;
  }
};

const App = () => {
  const [query, setQuery] = useState('');
  const [activeCategory, setActiveCategory] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [filteredIds, setFilteredIds] = useState<string[]>(MEDICAL_LINKS.map(l => l.id));

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!query.trim()) {
      setFilteredIds(MEDICAL_LINKS.map(l => l.id));
      return;
    }
    setLoading(true);
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `Filter these medical link IDs for query: "${query}". Return a JSON array of IDs. Enlaces: ${JSON.stringify(MEDICAL_LINKS.map(l => ({id: l.id, name: l.name, desc: l.description})))}`,
        config: {
          responseMimeType: "application/json",
          responseSchema: { type: Type.ARRAY, items: { type: Type.STRING } }
        }
      });
      const ids = JSON.parse(response.text || '[]');
      setFilteredIds(ids.length > 0 ? ids : MEDICAL_LINKS.filter(l => l.name.toLowerCase().includes(query.toLowerCase())).map(l => l.id));
    } catch (err) {
      setFilteredIds(MEDICAL_LINKS.filter(l => l.name.toLowerCase().includes(query.toLowerCase())).map(l => l.id));
    } finally {
      setLoading(false);
    }
  };

  const handleCatSelect = (cat: string | null) => {
    setActiveCategory(cat);
    setQuery('');
    if (cat === null) setFilteredIds(MEDICAL_LINKS.map(l => l.id));
    else setFilteredIds(MEDICAL_LINKS.filter(l => l.category === cat).map(l => l.id));
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
  };

  return (
    <div>
      <nav className="sticky top-0 z-50 bg-white border-b border-slate-200">
        <div className="max-w-full mx-auto flex items-center justify-between gap-6 px-8 py-2">
          <div className="flex items-center gap-2 cursor-pointer">
            <div className="w-8 h-8 bg-sky-600 rounded-lg flex items-center justify-center text-white">
              <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M3 21h18M3 7v1a3 3 0 0 0 6 0V4m0 4v1a3 3 0 0 0 6 0V4m0 4v1a3 3 0 0 0 6 0V4M9 21V4M15 21V4"/></svg>
            </div>
            <div className="font-display font-bold text-base tracking-tight text-slate-800">VIVA1A <span className="text-sky-400 ml-0.5">PORTAL</span></div>
          </div>

          <form className="flex items-center bg-slate-100 rounded-lg p-0.5 w-72 transition-all focus-within:bg-white focus-within:ring-2 focus-within:ring-sky-300" onSubmit={handleSearch}>
            <input 
              type="text" 
              className="flex-1 bg-transparent border-none px-2.5 py-1.5 outline-none text-sm text-slate-800 placeholder-slate-400" 
              placeholder="Buscar..." 
              value={query}
              onChange={(e) => setQuery(e.target.value)}
            />
            <button type="submit" className="bg-sky-600 text-white border-none px-2.5 py-1 rounded-md font-bold text-xs cursor-pointer disabled:opacity-50" disabled={loading}>
              {loading ? '...' : 'IA'}
            </button>
          </form>

          <div className="flex bg-slate-100 p-1 rounded-xl gap-0.5">
            {['Todos', 'Asistenciales', 'Operativos', 'Capacitación', 'Soporte'].map(cat => (
              <button 
                key={cat}
                className={`flex items-center gap-1.5 border-none px-3.5 py-1.5 rounded-lg font-semibold text-sm transition-all
                  ${(activeCategory === cat || (cat === 'Todos' && activeCategory === null)) ? 'bg-sky-600 text-white' : 'bg-transparent text-slate-500'}`}
                onClick={() => handleCatSelect(cat === 'Todos' ? null : cat as CategoryType)}
              >
                <div className="w-4 h-4"><CategoryIcon type={cat} /></div>
                <span>{cat}</span>
              </button>
            ))}
          </div>

          <div className="border border-slate-200 px-3 py-1 rounded-lg text-xs font-bold text-slate-400 uppercase">ESPECIALISTA V4.12</div>
        </div>
      </nav>

      <div className="flex max-w-full">
        <main className="flex-1 p-10 px-12">
          <header className="mb-8">
            <h1 className="font-display text-3xl font-bold text-slate-800">Portal de <span className="text-sky-400">Herramientas</span></h1>
            <p className="text-slate-500 text-base mt-1">Acceso directo a las plataformas operativas de la IPS.</p>
          </header>

          <div className="grid grid-cols-[repeat(auto-fill,minmax(280px,1fr))] gap-6">
            <AnimatePresence>
              {MEDICAL_LINKS.filter(l => filteredIds.includes(l.id)).map((link) => (
                <motion.a
                  key={link.id}
                  href={link.url}
                  target="_blank"
                  rel="noopener noreferrer"
                  layout
                  initial={{ opacity: 0, y: 10 }}
                  animate={{ opacity: 1, y: 0 }}
                  exit={{ opacity: 0, scale: 0.95 }}
                  className="group bg-white border border-slate-100 rounded-2xl p-5 flex flex-col relative transition-all ease-in-out duration-200 hover:shadow-lg hover:border-slate-200"
                >
                  <div className="flex justify-between items-start mb-4">
                    <div className="w-12 h-12 bg-slate-50 rounded-xl flex items-center justify-center text-slate-500">
                       <div className="w-6 h-6"><CategoryIcon type={link.category} /></div>
                    </div>
                    <div className="w-8 h-8 bg-slate-50 rounded-full flex items-center justify-center text-slate-300 text-xl transition-all group-hover:bg-slate-100 group-hover:text-sky-600">&#8594;</div>
                  </div>
                  <div>
                    <h4 className="font-display text-sm font-bold uppercase tracking-wider mb-2 text-slate-800">{link.name}</h4>
                    <p className="text-slate-500 text-sm leading-relaxed min-h-[3.5rem]">{link.description}</p>
                  </div>
                  <div className="mt-4">
                    <span className="text-xs font-bold uppercase tracking-wider bg-slate-100 px-2.5 py-1 rounded-md text-slate-400">{link.category}</span>
                  </div>
                </motion.a>
              ))}
            </AnimatePresence>
          </div>
        </main>

        <aside className="w-96 p-8 flex-col gap-8 bg-slate-50/50 border-l border-slate-200 hidden xl:flex">
          <div className="bg-indigo-600 rounded-3xl p-8 text-white text-center flex flex-col items-center">
            <div className="w-14 h-14 bg-white/10 rounded-2xl flex items-center justify-center mb-6">
              <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M21 11.5a8.38 8.38 0 0 1-.9 3.8 8.5 8.5 0 1 1-7.6-11.7 8.38 8.38 0 0 1 3.8.9L21 3z"/></svg>
            </div>
            <h2 className="font-display text-3xl font-bold mb-2">Soporte TI</h2>
            <p className="text-sm opacity-90 mb-6 leading-snug max-w-[200px]">Atención inmediata para problemas técnicos, bloqueos de usuario o fallos de sistema.</p>
            <a href="#" className="w-full bg-green-500 text-white no-underline py-3.5 rounded-2xl font-bold text-sm uppercase flex items-center justify-center gap-2 mb-4">
               <svg className="w-5 h-5" viewBox="0 0 24 24" fill="currentColor"><path d="M17.472 14.382c-.297-.149-1.758-.867-2.03-.967-.273-.099-.471-.148-.67.15-.197.297-.767.966-.94 1.164-.173.199-.347.223-.644.075-.297-.15-1.255-.463-2.39-1.475-.883-.788-1.48-1.761-1.653-2.059-.173-.297-.018-.458.13-.606.134-.133.298-.347.446-.52.149-.174.198-.298.298-.497.099-.198.05-.371-.025-.52-.075-.149-.669-1.612-.916-2.207-.242-.579-.487-.5-.669-.51-.173-.008-.371-.01-.57-.01-.198 0-.52.074-.792.372-.272.297-1.04 1.016-1.04 2.479 0 1.462 1.065 2.875 1.213 3.074.149.198 2.096 3.2 5.077 4.487.709.306 1.262.489 1.694.625.712.227 1.36.195 1.871.118.571-.085 1.758-.719 2.006-1.413.248-.694.248-1.289.173-1.413-.074-.124-.272-.198-.57-.347m-5.421 7.403h-.004a9.87 9.87 0 01-5.031-1.378l-.361-.214-3.741.982.998-3.648-.235-.374a9.86 9.86 0 01-1.51-5.26c.001-5.45 4.436-9.884 9.888-9.884 2.64 0 5.122 1.03 6.988 2.898a9.825 9.825 0 012.893 6.994c-.003 5.45-4.437 9.884-9.885 9.884m8.413-18.297A11.815 11.815 0 0012.05 0C5.495 0 .16 5.335.157 11.892c0 2.096.547 4.142 1.588 5.945L0 24l6.335-1.662c1.72.937 3.659 1.431 5.63 1.432h.005c6.554 0 11.89-5.335 11.893-11.893a11.821 11.821 0 00-3.48-8.413Z"/></svg>
              SOPORTE WHATSAPP
            </a>
            <a href="http://mesadeservicios.viva1a.com.co/glpi/index.php" className="text-xs font-bold uppercase tracking-widest text-white/60 no-underline">MESA DE SERVICIO GLPI</a>
          </div>

          <div>
            <div className="text-xs font-bold uppercase tracking-widest text-slate-400 flex items-center gap-2 mb-4">
              <div className="w-1 h-1 bg-sky-600 rounded-full"></div>
              CREDENCIALES
            </div>
            {CREDENTIALS.map(cred => (
              <div key={cred.name} className="bg-white border border-slate-100 rounded-2xl p-5 mb-4 relative overflow-hidden">
                <div className="absolute left-0 top-0 bottom-0 w-1" style={{ backgroundColor: cred.color }}></div>
                <div className="flex items-center gap-3 mb-4">
                  <span className="text-2xl">{cred.icon}</span>
                  <span className="font-bold text-base text-slate-800">{cred.name}</span>
