const App = () => {
  const [query, setQuery] = useState('');
  const [filteredIds, setFilteredIds] = useState<string[]>(MEDICAL_LINKS.map(l => l.id));
  const [activeCategory, setActiveCategory] = useState<string | null>(null);
  const [isAiLoading, setIsAiLoading] = useState(false);

  const categories = ['Asistenciales', 'Operativos', 'Capacitación', 'Soporte'];

  const handleSearch = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    setActiveCategory(null);

    if (!query.trim()) {
      setFilteredIds(MEDICAL_LINKS.map(l => l.id));
      return;
    }

    setIsAiLoading(true);
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    try {
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `Eres un asistente experto para médicos en la IPS Viva1A. 
        Analiza la intención del usuario: "${query}". 
        Debes filtrar los siguientes enlaces y devolver ÚNICAMENTE un array JSON con los IDs de los enlaces que coincidan semánticamente con la búsqueda.

        Enlaces disponibles: ${JSON.stringify(MEDICAL_LINKS.map(l => ({ id: l.id, name: l.name, description: l.description, keywords: l.keywords })))}`,
        config: {
          responseMimeType: "application/json",
          responseSchema: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING } 
          }
        }
      });

      const resultText = response.text || '[]';
      const resultIds = JSON.parse(resultText);

      if (Array.isArray(resultIds) && resultIds.length > 0) {
        setFilteredIds(resultIds);
      } else {
        // Fallback simple si la IA no devuelve resultados útiles
        const fallback = MEDICAL_LINKS.filter(l => 
          l.name.toLowerCase().includes(query.toLowerCase()) || 
          l.description.toLowerCase().includes(query.toLowerCase()) ||
          l.keywords.some(k => k.toLowerCase().includes(query.toLowerCase()))
        ).map(l => l.id);
        setFilteredIds(fallback);
      }
    } catch (err) {
      console.error("Error en búsqueda IA:", err);
      // Fallback a búsqueda local básica
      const localResults = MEDICAL_LINKS.filter(l => 
        l.name.toLowerCase().includes(query.toLowerCase()) || 
        l.description.toLowerCase().includes(query.toLowerCase())
      ).map(l => l.id);
      setFilteredIds(localResults);
    } finally {
      setIsAiLoading(false);
    }
  };

  const handleCategoryClick = (cat: string | null) => {
    setQuery('');
    if (activeCategory === cat) {
      setActiveCategory(null);
      setFilteredIds(MEDICAL_LINKS.map(l => l.id));
    } else {
      setActiveCategory(cat);
      if (cat === null) {
        setFilteredIds(MEDICAL_LINKS.map(l => l.id));
      } else {
        setFilteredIds(MEDICAL_LINKS.filter(l => l.category === cat).map(l => l.id));
      }
    }
  };

  const displayedLinks = useMemo(() => 
    MEDICAL_LINKS.filter(l => filteredIds.includes(l.id)), 
    [filteredIds]
  );

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 font-sans flex flex-col relative overflow-hidden">
      {/* Background Decor */}
      <div className="fixed inset-0 pointer-events-none z-0">
        <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-blue-100 rounded-full blur-[120px] opacity-40 animate-pulse"></div>
        <div className="absolute bottom-[-10%] right-[-10%] w-[35%] h-[35%] bg-indigo-100 rounded-full blur-[100px] opacity-30"></div>
      </div>

      <nav className="bg-white/90 backdrop-blur-md border-b border-slate-200 sticky top-0 z-40 px-6 py-4 shadow-sm">
        <div className="max-w-[1900px] mx-auto flex flex-col xl:flex-row items-center justify-between gap-6">

          <div className="flex items-center gap-6 shrink-0 w-full xl:w-auto">
            <div className="flex items-center gap-3">
              <motion.div 
                whileHover={{ scale: 1.1, rotate: 10 }}
                className="w-10 h-10 bg-gradient-to-br from-[#0077b6] to-indigo-700 rounded-xl flex items-center justify-center shadow-lg shadow-blue-200"
              >
                <svg className="w-6 h-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M19 21V5a2 2 0 00-2-2H7a2 2 0 00-2 2v16m14 0h2m-2 0h-5m-9 0H3m2 0h5M9 7h1m-1 4h1m4-4h1m-1 4h1m-5 10v-5a1 1 0 011-1h2a1 1 0 011 1v5m-4 0h4" /></svg>
              </motion.div>
              <h1 className="text-xl font-black tracking-tight text-slate-800 uppercase">VIVA1A <span className="text-[#0077b6]">PORTAL</span></h1>
            </div>

            <form onSubmit={handleSearch} className="relative group flex-1 max-w-[400px]">
              <div className={`absolute -inset-0.5 bg-gradient-to-r from-[#0077b6] to-indigo-500 rounded-xl blur ${isAiLoading ? 'opacity-50' : 'opacity-10'} group-focus-within:opacity-25 transition duration-500`}></div>
              <div className={`relative flex items-center bg-slate-100 border border-slate-200 rounded-xl p-0.5 transition-all focus-within:bg-white focus-within:border-[#0077b6] ${isAiLoading ? 'cursor-wait' : ''}`}>
                <div className="pl-3 text-slate-400">
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"/></svg>
                </div>
                <input
                  type="text"
                  value={query}
                  onChange={(e) => setQuery(e.target.value)}
                  placeholder="¿Qué necesitas buscar hoy? (ej: reportar fallas)"
                  className="w-full bg-transparent px-2 py-2 outline-none text-slate-700 text-sm font-semibold placeholder:text-slate-400"
                />
                <button 
                  type="submit" 
                  disabled={isAiLoading}
                  className={`relative flex items-center gap-2 overflow-hidden px-4 py-2 rounded-lg font-bold transition-all text-[11px] active:scale-95 disabled:opacity-70 ${isAiLoading ? 'bg-slate-200 text-slate-400' : 'bg-[#0077b6] text-white hover:bg-[#005f91]'}`}
                >
                  {isAiLoading ? (
                    <motion.div 
                      animate={{ rotate: 360 }} 
                      transition={{ repeat: Infinity, duration: 1, ease: "linear" }}
                      className="w-3 h-3 border-2 border-white/30 border-t-white rounded-full"
                    />
                  ) : (
                    <svg className="w-3 h-3" fill="currentColor" viewBox="0 0 20 20"><path d="M10 12a2 2 0 100-4 2 2 0 000 4z"/><path fillRule="evenodd" d="M.458 10C1.732 5.943 5.522 3 10 3s8.268 2.943 9.542 7c-1.274 4.057-5.064 7-9.542 7S1.732 14.057.458 10zM14 10a4 4 0 11-8 0 4 4 0 018 0z" clipRule="evenodd"/></svg>
                  )}
                  <span>IA</span>
                </button>
              </div>
            </form>
          </div>

          <div className="bg-[#e9eff5] p-1.5 rounded-2xl flex items-center shadow-inner overflow-x-auto no-scrollbar">
            <button
              onClick={() => handleCategoryClick(null)}
              className={`flex items-center gap-2.5 px-6 py-2.5 rounded-[14px] transition-all duration-300 font-bold text-sm whitespace-nowrap ${
                activeCategory === null ? 'bg-[#0077b6] text-white shadow-lg' : 'text-[#475569] hover:bg-white/50'
              }`}
            >
              <CategoryIcon type="Todos" active={activeCategory === null} />
              <span>Todos</span>
            </button>
            {categories.map((cat) => (
              <button
